args.command:
node -e "
const fs = require('fs');
const original = {\"items\":[{\"id\":1,\"name\":\"alpha\"},{\"id\":2,\"name\":\"beta\"},{\"id\":3,\"name\":\"gamma\"}]};
const current = JSON.parse(fs.readFileSync('data.json', 'utf8'));

// Deep equality check for objects
function deepEqual(obj1, obj2) {
  return JSON.stringify(obj1, Object.keys(obj1).sort()) === JSON.stringify(obj2, Object.keys(obj2).sort());
}

console.log('Semantic equivalence (order-independent): ', deepEqual(original, current));

// Verify indentation
const content = fs.readFileSync('data.json', 'utf8');
const lines = content.split('\n');
console.log('Total lines:', lines.length);
console.log('Has trailing newline:', content.endsWith('\n'));

// Check indentation levels
const indent2Matches = content.match(/^  [^]/gm) || [];
console.log('2-space indented lines:', indent2Matches.length);

const indent4Matches = content.match(/^    [^ ]/gm) || [];
console.log('4-space indented lines:', indent4Matches.length);

// Verify key order in items
console.log('\nKey order verification:');
current.items.forEach((item, i) => {
  const keys = Object.keys(item);
  console.log(\`  Item \${i}: [\${keys.join(', ')}]\`);
  console.log(\`  Order correct (name, id)?: \${keys[0] === 'name' && keys[1] === 'id'}\`);
});
"
